mapper.select:
SELECT * FROM ldap_configurations
WHERE customer_id = #{customerId}
LIMIT 1

mapper.update:
UPDATE ldap_configurations
SET last_sync_at = NOW(), updated_at = NOW()
WHERE id = #{id} AND customer_id = #{customerId}

mapper.insert:
INSERT INTO ldap_group_mappings (
    ldap_config_id, ldap_group_dn, local_role, local_configuration_id, priority, created_at
) VALUES (
    #{ldapConfigId}, #{ldapGroupDn}, #{localRole}, #{localConfigurationId}, COALESCE(#{priority}, 0), NOW()
)

INSERT INTO ldap_sync_logs (
    customer_id, sync_type, status, users_synced, users_created, users_updated, users_failed,
    error_message, started_at, completed_at
) VALUES (
    #{customerId}, #{syncType}, #{status}, #{usersSynced}, #{usersCreated}, #{usersUpdated}, #{usersFailed},
    #{errorMessage}, COALESCE(#{startedAt}, NOW()), #{completedAt}
)

mapper.select:
SELECT * FROM ldap_sync_logs
WHERE customer_id = #{customerId}
ORDER BY started_at DESC

SELECT * FROM ldap_sync_logs
WHERE customer_id = #{customerId}
ORDER BY started_at DESC
LIMIT #{limit}

mapper.update:
UPDATE users
SET ldap_user = #{ldapUser}, ldap_dn = #{ldapDn}, ldap_synced_at = NOW()
WHERE id = #{userId}

UPDATE users
SET ldap_user = TRUE, ldap_dn = #{ldapDn}, ldap_synced_at = NOW()
WHERE id = #{userId}
